oxy_webhelp_navlinks = {"rolling_upgrade_rbk_cdm_software-d30753e3461":{"topics":[{"title":"Advantages of using a rolling upgrade","shortdesc":"<p class=\"shortdesc\">With a rolling upgrade, you can upgrade a Rubrik cluster or third-party hardware         without downtime. Rolling upgrades provide a set of advantages, such as simplified upgrade         workflow, support for third-party hardware upgrades, and varied levels of job         resumability.<\/p>","href":"saas\/rolling_upgrade_advantages.html","attributes":{"data-id":"rolling_upgrade_advantages"},"menu":{"hasChildren":false},"tocID":"rolling_upgrade_advantages-d30753e3475","topics":[]},{"title":"Rolling upgrade statuses for workloads","shortdesc":"<p class=\"shortdesc\">Information about the statuses for workloads, such as resumable, restartable, and         unsupported, during a rolling upgrade.<\/p>","href":"saas\/rolling_upgrade_statuses.html","attributes":{"data-id":"rolling_upgrade_statuses"},"menu":{"hasChildren":false},"tocID":"rolling_upgrade_statuses-d30753e3486","topics":[]},{"title":"Enabling rolling upgrades for a Rubrik cluster","shortdesc":"<p class=\"shortdesc\">Enable the rolling upgrade capability for specific Rubrik clusters to make it         available during the software update process.<\/p>","href":"saas\/rolling_upgrade_enable.html","attributes":{"data-id":"rolling_upgrade_enable"},"menu":{"hasChildren":false},"tocID":"rolling_upgrade_enable-d30753e3497","topics":[]}]}};